  ('social-worker-moex-06500', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據Chris Trotter提到如何與非自願個案工作的有效工作方法，下列何者敘述為非？', '["清楚、誠實與頻繁地討論工作者與個案的角色", "示範與鼓勵個案從事利社會的表達與行為", "隨時面質個案出現的不一致語言或行為", "聚焦於個案自身對問題的定義與目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06501', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一個不是「優勢觀點」社會工作實務在進行個案評量時的正確描述？', '["個案處遇焦點強調優勢、想望和可用資源", "介入方向利基於優勢，以成長為導向", "針對預後設定服務結果，並對服藥順從性與精神症狀問題進行評量", "執行者是案主與專業人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06502', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一項「不是」兒童福利社工員從事監護權調查時，進行個案評估（assessment）的參考指標？', '["親職照顧能力", "夫妻性生活滿意度", "子女接受監護意願", "照顧者的正式與非正式社會支持網絡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06503', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社工員在進行案家家庭訪視時，意外發現二歲幼童遭受同居人身體虐待，社工員依規定向主管機關通報 後，後續主管機關應於接獲通報至遲多少時間內立即處理此案件？', '["12小時", "24小時", "48小時", "72小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06504', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在機構實施其專業，應掌握社會工作過程之主要要素，下列敘述何者正確？①專業的挑戰與', '["直接服務的基礎知識", "專業的價值觀與倫理", "服務的方法與過程  ⑤專業的目的", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06505', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者回應案主時使用「面質」（confrontation）技巧，下列敘述何者正確？①我覺得父親對你的關', '["看到你這樣的行為表現和我們所預期的目標差距很大", "從你剛剛的談話中 瞭解，現在家裡的問題不在於此", "看得出來你的眼神充滿憤怒，卻說不會生氣  ⑤你答應爸爸每天都 會到學校上課，但是從這星期一開始，你就沒有到學校", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06506', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '個案管理員的工作之一是指認與排除外在障礙，下列那些屬於「外在障礙」的類型：①找出悲觀論模式，', '["案主對於長達數頁的申請表格無從下手", "雖然該鄉鎮有辦理新住民團體，但卻遠 在距離案家20公里外的活動中心", "機構急難救助一年只能申請二次，案主已超過申請額度", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06507', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主：（15 歲女孩，極度希望入選學校排球隊，但最後未入選）很可惡！我不去上學了。我沒臉面對她 們，我多麼希望能成為校排隊員，這傷我很重，這真的傷害了我。社工：妳感到全然被拒絕了，妳真的 徹底失望了。請問這段個案會談的對話，較屬於個案晤談中的何項技術？', '["反映感受", "部分化", "面質", "尋求澄清"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06508', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者運用生態系統模型處遇個案時，其所指稱之「標的系統」（target system），下列敘述何者 正確？', '["連結目標機構的任何資源", "將必需加以改變的人和問題集合", "評估個案可能潛在的資源目標", "將個案的問題標的先後排序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06509', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '與個案會談初期進入尾聲，社會工作者在回顧整個會談過程中發現之問題，並明確指出與案主問題有關 的主題，進而試探與案主討論改變目標的可能性。此為下列何種會談反應技巧？', '["同理", "具體化", "摘要", "澄清"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "8fd6c60d6726", "answer_pdf_sha1": "2a0268297535", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
